    /// - Returns: The XML-safe string.
    public static func escapeXML(_ string: String) -> String {
        guard string.contains(where: { $0 == "&" || $0 == "<" || $0 == ">" || $0 == "\"" || $0 == "'" }) else {
            return string
        }

        var result = ""
        result.reserveCapacity(string.count + string.count / 8)
        for ch in string {
            switch ch {
            case "&":  result += "&amp;"
            case "<":  result += "&lt;"
            case ">":  result += "&gt;"
            case "\"": result += "&quot;"
            case "'":  result += "&apos;"
